/**
 * Backtest Runner — School of Pipsology "So Easy It's Ridiculous"
 */

import fs from "fs";
import { calculateIndicators } from "./indicators.js";
import { config } from "./config.js";

const INITIAL_BALANCE = 385; 
const COMMISSION_SIDE_USD = 3.00;
const SPREAD_PIPS = 0.5; 
const SLIPPAGE_PIPS = 0.2;

let balance = INITIAL_BALANCE;
const pairData = {};
const PAIRS = config.tradingPairs;

async function main() {
  console.log(`\n${"═".repeat(60)}`);
  console.log(`    SCHOOL OF PIPSOLOGY BACKTESTER`);
  console.log(`  Strategy : So Easy It's Ridiculous (H1 + M5)`);
  console.log(`  Pairs    : ${PAIRS.join(", ")}`);
  console.log(`${"═".repeat(60)}\n`);

  const allTimestamps = new Set();

  for (const pair of PAIRS) {
    const filename = `history_${pair.replace("/", "_")}.json`;
    if (!fs.existsSync(filename)) continue;
    let candles = JSON.parse(fs.readFileSync(filename, "utf8"));

    candles = candles.map(c => {
      if (!c.mid && c.bid && c.ask) {
        c.mid = {
          o: ((parseFloat(c.bid.o) + parseFloat(c.ask.o)) / 2).toFixed(5),
          h: ((parseFloat(c.bid.h) + parseFloat(c.ask.h)) / 2).toFixed(5),
          l: ((parseFloat(c.bid.l) + parseFloat(c.ask.l)) / 2).toFixed(5),
          c: ((parseFloat(c.bid.c) + parseFloat(c.ask.c)) / 2).toFixed(5),
        };
      }
      return c;
    });

    pairData[pair] = {
        candles,
        isJPY: pair.includes("JPY"),
        pipSize: pair.includes("JPY") ? 0.01 : 0.0001,
        activeTrades: [],
        tradeHistory: [],
        candleIndex: 0
    };
    candles.forEach(c => allTimestamps.add(c.time));
  }

  const sortedTimestamps = Array.from(allTimestamps).sort((a, b) => new Date(a) - new Date(b));
  const windowM5 = 400;

  for (const timestamp of sortedTimestamps) {
    for (const pair of PAIRS) {
      const p = pairData[pair];
      if (!p) continue;

      while (p.candleIndex < p.candles.length && p.candles[p.candleIndex].time < timestamp) p.candleIndex++;
      if (p.candleIndex >= p.candles.length || p.candles[p.candleIndex].time !== timestamp || p.candleIndex < windowM5) continue;

      const currentM5Candles = p.candles.slice(p.candleIndex - windowM5, p.candleIndex);
      const nextCandle = p.candles[p.candleIndex];

      const h1Candles = [];
      for (let i = 0; i <= currentM5Candles.length - 12; i += 12) {
        const chunk = currentM5Candles.slice(i, i + 12);
        h1Candles.push({
          mid: {
            o: chunk[0].mid.o,
            h: Math.max(...chunk.map(c => parseFloat(c.mid.h))).toString(),
            l: Math.min(...chunk.map(c => parseFloat(c.mid.l))).toString(),
            c: chunk[chunk.length - 1].mid.c
          }
        });
      }
      if (h1Candles.length < 15) continue;

      const indM5 = calculateIndicators(currentM5Candles);
      const indH1 = calculateIndicators(h1Candles);

      const midOpen = parseFloat(nextCandle.mid.o);
      const midHigh = parseFloat(nextCandle.mid.h);
      const midLow  = parseFloat(nextCandle.mid.l);

      const spread = SPREAD_PIPS * p.pipSize;
      const bidLow  = midLow - spread/2;
      const bidHigh = midHigh - spread/2;
      const askHigh = midHigh + spread/2;
      const askLow  = midLow + spread/2;

      // Manage trades
      p.activeTrades = p.activeTrades.filter(trade => {
        if (trade.direction === "BUY") {
          if (bidLow <= trade.sl) { closeTrade(pair, trade, trade.sl, "SL", timestamp); return false; }
          if (bidHigh >= trade.tp) { closeTrade(pair, trade, trade.tp, "TP", timestamp); return false; }
        } else {
          if (askHigh >= trade.sl) { closeTrade(pair, trade, trade.sl, "SL", timestamp); return false; }
          if (askLow <= trade.tp) { closeTrade(pair, trade, trade.tp, "TP", timestamp); return false; }
        }
        return true;
      });

      // Session Hours (12:00-16:00 UTC)
      const dateObj = new Date(timestamp);
      const h = dateObj.getUTCHours();
      if (dateObj.getUTCDay() === 0 || dateObj.getUTCDay() === 6 || h < config.sessionStartUTC || h >= config.sessionEndUTC) continue;

      // Logic
      const htfTrend = indH1.ema5 > indH1.ema10 ? "BULLISH" : "BEARISH";
      let action = "WAIT";
      if (indM5.ema5 > indM5.ema10 && indM5.isStochHeadingUp && !indM5.isStochOverbought && indM5.rsi > 50 && htfTrend === "BULLISH") action = "BUY";
      if (indM5.ema5 < indM5.ema10 && indM5.isStochHeadingDown && !indM5.isStochOversold && indM5.rsi < 50 && htfTrend === "BEARISH") action = "SELL";

      if (action !== "WAIT" && p.activeTrades.length < config.maxTradesPerPair) {
         handleSignal(pair, action, midOpen, indM5, timestamp);
      }
    }
  }

  function handleSignal(pair, action, price, ind, time) {
    const p = pairData[pair];
    const slPips = Math.max(config.minStopDistancePips, (ind.atr / p.pipSize) * config.strategy.atrMultiplierSL);
    const tpPips = slPips * config.risk.minRiskReward;

    const entryPrice = action === "BUY" ? price + (SLIPPAGE_PIPS * p.pipSize) : price - (SLIPPAGE_PIPS * p.pipSize);
    const units = Math.min(10000, Math.floor((INITIAL_BALANCE * 0.02) / (slPips * (10/100000))));

    p.activeTrades.push({
      direction: action,
      entry: entryPrice,
      sl: action === "BUY" ? entryPrice - (slPips * p.pipSize) : entryPrice + (slPips * p.pipSize),
      tp: action === "BUY" ? entryPrice + (tpPips * p.pipSize) : entryPrice - (tpPips * p.pipSize),
      units,
      time
    });
  }

  function closeTrade(pair, trade, exitPrice, reason, exitTime) {
    const p = pairData[pair];
    const diff = trade.direction === "BUY" ? (exitPrice - trade.entry) : (trade.entry - exitPrice);
    const pips = diff / p.pipSize;
    const profit = (pips * (10/100000)) * trade.units;
    balance += profit;
    p.tradeHistory.push({ ...trade, exit: exitPrice, exitTime, reason, profit });
    console.log(`  ✅ [${exitTime}] ${pair} ${reason} | Net: $${profit.toFixed(2)} | Bal: $${balance.toFixed(2)}`);
  }

  const allHistory = Object.values(pairData).flatMap(p => p.tradeHistory);
  console.log(`\n   FINAL: $${balance.toFixed(2)} | Trades: ${allHistory.length} | Win Rate: ${((allHistory.filter(t => t.profit > 0).length / allHistory.length) * 100).toFixed(1)}%\n`);
}

main().catch(console.error);

/**
 * Backtest Runner — 5-10-20 EMA Scalping Strategy (Multi-Pair)
 */

import fs from "fs";
import { generateSignal } from "./indicators.js";
import { config } from "./config.js";

const INITIAL_BALANCE = 385; 
const COMMISSION_SIDE_USD = 3.00;
const SPREAD_PIPS = 0.5; 
const SLIPPAGE_PIPS = 0.2;

let balance = INITIAL_BALANCE;
const pairData = {};
const PAIRS = config.tradingPairs;

async function main() {
  console.log(`\n${"═".repeat(60)}`);
  console.log(`    5-10-20 EMA SCALPING BACKTESTER (MULTI-PAIR)`);
  console.log(`  Pairs    : ${PAIRS.join(", ")}`);
  console.log(`${"═".repeat(60)}\n`);

  const allTimestamps = new Set();

  for (const pair of PAIRS) {
    const filename = `history_${pair.replace("/", "_")}.json`;
    if (!fs.existsSync(filename)) continue;
    let candles = JSON.parse(fs.readFileSync(filename, "utf8"));

    candles = candles.map(c => {
      if (!c.mid && c.bid && c.ask) {
        c.mid = {
          o: ((parseFloat(c.bid.o) + parseFloat(c.ask.o)) / 2).toFixed(5),
          h: ((parseFloat(c.bid.h) + parseFloat(c.ask.h)) / 2).toFixed(5),
          l: ((parseFloat(c.bid.l) + parseFloat(c.ask.l)) / 2).toFixed(5),
          c: ((parseFloat(c.bid.c) + parseFloat(c.ask.c)) / 2).toFixed(5),
        };
      }
      return c;
    });

    pairData[pair] = {
        candles,
        isJPY: pair.includes("JPY"),
        pipSize: pair.includes("JPY") ? 0.01 : 0.0001,
        activeTrades: [],
        tradeHistory: [],
        candleIndex: 0
    };
    candles.forEach(c => allTimestamps.add(c.time));
  }

  const sortedTimestamps = Array.from(allTimestamps).sort((a, b) => new Date(a) - new Date(b));
  const windowM5 = 100;

  for (const timestamp of sortedTimestamps) {
    for (const pair of PAIRS) {
      const p = pairData[pair];
      if (!p) continue;

      while (p.candleIndex < p.candles.length && p.candles[p.candleIndex].time < timestamp) p.candleIndex++;
      if (p.candleIndex >= p.candles.length || p.candles[p.candleIndex].time !== timestamp || p.candleIndex < windowM5) continue;

      const currentM5Candles = p.candles.slice(p.candleIndex - windowM5, p.candleIndex);
      const nextCandle = p.candles[p.candleIndex];

      const midOpen = parseFloat(nextCandle.mid.o);
      const midHigh = parseFloat(nextCandle.mid.h);
      const midLow  = parseFloat(nextCandle.mid.l);

      const spread = SPREAD_PIPS * p.pipSize;
      const bidLow  = midLow - spread/2;
      const bidHigh = midHigh - spread/2;
      const askHigh = midHigh + spread/2;
      const askLow  = midLow + spread/2;

      // Manage trades
      p.activeTrades = p.activeTrades.filter(trade => {
        if (trade.direction === "BUY") {
          if (bidLow <= trade.sl) { closeTrade(pair, trade, trade.sl, "SL", timestamp); return false; }
          if (bidHigh >= trade.tp) { closeTrade(pair, trade, trade.tp, "TP", timestamp); return false; }
        } else {
          if (askHigh >= trade.sl) { closeTrade(pair, trade, trade.sl, "SL", timestamp); return false; }
          if (askLow <= trade.tp) { closeTrade(pair, trade, trade.tp, "TP", timestamp); return false; }
        }
        return true;
      });

      // Session Hours (supports multi-window UTC, incl. half-hours)
      const dateObj = new Date(timestamp);
      if (dateObj.getUTCDay() === 0 || dateObj.getUTCDay() === 6 || !isTradeWindowUTC(dateObj)) continue;

      // Signal Generation
      const signal = generateSignal(currentM5Candles, {
        pipBuffer: config.strategy.pipBuffer,
        rrRatio:   config.strategy.rrRatio,
        isJPY:     p.isJPY,
      });

      if (signal.signal === 'none' || p.activeTrades.length >= config.maxTradesPerPair) continue;

      handleSignal(pair, signal, midOpen, timestamp);
    }
  }

  function handleSignal(pair, signal, price, time) {
    const p = pairData[pair];
    const action = signal.signal.toUpperCase();
    const units = Math.min(10000, Math.floor((INITIAL_BALANCE * 0.02) / (signal.riskPips * (10/100000))));

    p.activeTrades.push({
      direction: action,
      entry: signal.entry,
      sl: signal.sl,
      tp: signal.tp,
      units,
      time,
      pair,
      reason: signal.reason,
    });
  }

  function closeTrade(pair, trade, exitPrice, reason, exitTime) {
    const p = pairData[pair];
    const diff = trade.direction === "BUY" ? (exitPrice - trade.entry) : (trade.entry - exitPrice);
    const pips = diff / p.pipSize;
    const profit = (pips * (10/100000)) * trade.units;
    balance += profit;
    p.tradeHistory.push({ ...trade, exit: exitPrice, exitTime, reason, profit, balance });
    console.log(`  ✅ [${exitTime}] ${pair} ${reason} | Net: $${profit.toFixed(2)} | Bal: $${balance.toFixed(2)}`);
  }

  const allHistory = Object.values(pairData).flatMap(p => p.tradeHistory);
  const wins = allHistory.filter(t => t.profit > 0);

  const finalStats = {
    type: "backtest",
    pairs: PAIRS,
    trades: allHistory,
    summary: {
      total: allHistory.length,
      wins: wins.length,
      losses: allHistory.length - wins.length,
      winRate: allHistory.length > 0 ? ((wins.length / allHistory.length) * 100).toFixed(1) : 0,
      netProfit: balance - INITIAL_BALANCE,
      finalBalance: balance,
    }
  };

  fs.writeFileSync("trades_backtest.json", JSON.stringify(finalStats, null, 2));

  console.log(`\n   FINAL: $${balance.toFixed(2)} | Trades: ${allHistory.length} | Win Rate: ${finalStats.summary.winRate}%`);
  console.log(`   Data saved to trades_backtest.json\n`);
}

function isTradeWindowUTC(dateObj) {
  const windows = config.sessionWindowsUTC;
  const h = dateObj.getUTCHours() + (dateObj.getUTCMinutes() / 60);

  if (Array.isArray(windows) && windows.length > 0) {
    return windows.some(w => h >= w.start && h < w.end);
  }

  return h >= config.sessionStartUTC && h < config.sessionEndUTC;
}

main().catch(console.error);

/**
 * Single-Pair Backtest Runner — 5-10-20 EMA Scalping Strategy
 */

import fs from "fs";
import { generateSignal } from "./indicators.js";
import { config } from "./config.js";

const PAIR = config.defaultInstrument || "EUR_USD";
const HISTORY_FILE = `history_${PAIR.replace("/", "_")}.json`;
const INITIAL_BALANCE = 385;
const PIP_SIZE = PAIR.includes("JPY") ? 0.01 : 0.0001;
const SPREAD = 0.5 * PIP_SIZE;
const SLIPPAGE = 0.2 * PIP_SIZE;

async function main() {
  if (!fs.existsSync(HISTORY_FILE)) {
    console.error(`❌ History file not found: ${HISTORY_FILE}`);
    process.exit(1);
  }

  let allCandles = JSON.parse(fs.readFileSync(HISTORY_FILE, "utf8"));
  allCandles = allCandles.map(c => {
    if (!c.mid && c.bid && c.ask) {
      c.mid = {
        o: ((parseFloat(c.bid.o) + parseFloat(c.ask.o)) / 2).toFixed(5),
        h: ((parseFloat(c.bid.h) + parseFloat(c.ask.h)) / 2).toFixed(5),
        l: ((parseFloat(c.bid.l) + parseFloat(c.ask.l)) / 2).toFixed(5),
        c: ((parseFloat(c.bid.c) + parseFloat(c.ask.c)) / 2).toFixed(5),
      };
    }
    return c;
  });

  console.log(`\n${"═".repeat(60)}`);
  console.log(`    5-10-20 EMA SCALPING BACKTESTER (SINGLE)`);
  console.log(`  Pair      : ${PAIR}`);
  console.log(`${"═".repeat(60)}\n`);

  let balance = INITIAL_BALANCE;
  let activeTrades = [];
  let tradeHistory = [];
  const windowM5 = 100;

  for (let i = windowM5; i < allCandles.length; i++) {
    const currentM5Candles = allCandles.slice(i - windowM5, i);
    const nextCandle = allCandles[i];
    const timestamp = nextCandle.time;

    const midOpen = parseFloat(nextCandle.mid.o);

    // Manage Trades
    activeTrades = activeTrades.filter(trade => {
      const bidLow = parseFloat(nextCandle.mid.l) - SPREAD/2;
      const bidHigh = parseFloat(nextCandle.mid.h) - SPREAD/2;
      const askHigh = parseFloat(nextCandle.mid.h) + SPREAD/2;
      const askLow = parseFloat(nextCandle.mid.l) + SPREAD/2;

      if (trade.direction === "BUY") {
        if (bidLow <= trade.sl) { closeTrade(trade, trade.sl, "SL", timestamp); return false; }
        if (bidHigh >= trade.tp) { closeTrade(trade, trade.tp, "TP", timestamp); return false; }
      } else {
        if (askHigh >= trade.sl) { closeTrade(trade, trade.sl, "SL", timestamp); return false; }
        if (askLow <= trade.tp) { closeTrade(trade, trade.tp, "TP", timestamp); return false; }
      }
      return true;
    });

    // Session Hours (12:00-16:00 UTC)
    const dateObj = new Date(timestamp);
    const h = dateObj.getUTCHours();
    if (dateObj.getUTCDay() === 0 || dateObj.getUTCDay() === 6 || h < config.sessionStartUTC || h >= config.sessionEndUTC) continue;

    // Signal Generation
    const signal = generateSignal(currentM5Candles, {
      pipBuffer: config.strategy.pipBuffer,
      rrRatio:   config.strategy.rrRatio,
      isJPY:     PAIR.includes("JPY"),
    });

    if (signal.signal === 'none' || activeTrades.length >= config.maxTradesPerPair) continue;

    const action = signal.signal.toUpperCase();
    const units = Math.min(10000, Math.floor((INITIAL_BALANCE * 0.02) / (signal.riskPips * (10/100000))));

    const trade = {
      direction: action,
      entry: signal.entry,
      sl: signal.sl,
      tp: signal.tp,
      units,
      id: `T${tradeHistory.length + 1}`,
      pair: PAIR,
      reason: signal.reason,
    };
    activeTrades.push(trade);
  }

  function closeTrade(trade, exitPrice, reason, time) {
    const diff = trade.direction === "BUY" ? (exitPrice - trade.entry) : (trade.entry - exitPrice);
    const pips = diff / PIP_SIZE;
    const profit = (pips * (10/100000)) * trade.units;
    balance += profit;
    tradeHistory.push({ ...trade, profit, reason, time, exitTime: time, exit: exitPrice, balance });
    console.log(`  ✅ [${time}] ${reason} at ${exitPrice.toFixed(5)} | Net: $${profit.toFixed(2)} | Bal: $${balance.toFixed(2)}`);
  }

  const wins = tradeHistory.filter(t => t.profit > 0);
  const finalStats = {
    type: "backtest",
    pair: PAIR,
    trades: tradeHistory,
    summary: {
      total: tradeHistory.length,
      wins: wins.length,
      losses: tradeHistory.length - wins.length,
      winRate: tradeHistory.length > 0 ? ((wins.length / tradeHistory.length) * 100).toFixed(1) : 0,
      netProfit: balance - INITIAL_BALANCE,
      finalBalance: balance,
    }
  };

  fs.writeFileSync("trades_backtest.json", JSON.stringify(finalStats, null, 2));

  console.log(`\n   FINAL: $${balance.toFixed(2)} | Trades: ${tradeHistory.length} | Win Rate: ${finalStats.summary.winRate}%`);
  console.log(`   Data saved to trades_backtest.json\n`);
}

main().catch(console.error);

