  .bg-muted { background: rgba(148, 163, 184, 0.1); color: var(--muted); border: 1px solid rgba(148, 163, 184, 0.2); }

  .flex-row { display: grid; grid-template-columns: 2fr 1fr; gap: 1.5rem; margin-top: 1.5rem; }
  @media (max-width: 850px) { .flex-row { grid-template-columns: 1fr; } .grid-stats { grid-template-columns: 1fr 1fr; } }
</style>
</head>
<body>

<div class="container">
  <header>
    <div>
      <h1>Trading Performance Terminal</h1>
      <p class="subtitle">System Analytics: ${formatDatePretty(trades[0].time)} to ${formatDatePretty(trades[trades.length-1].time)}</p>
    </div>
    <div class="subtitle" style="text-align: right;">Currency: KES &nbsp; | &nbsp; Rate: ${KES_RATE}</div>
  </header>

  <div class="grid-stats">
    <div class="card">
      <div class="label">Total Net P&L</div>
      <div class="value" style="color: ${netProfitKES >= 0 ? 'var(--success)' : 'var(--danger)'}">${netProfitKES >= 0 ? '+' : ''}${formatKES(netProfitKES)}</div>
      <div class="sub-value" style="color: var(--muted)">Growth: ${roi}% ROI</div>
    </div>
    <div class="card">
      <div class="label">Accuracy</div>
      <div class="value" style="color: var(--primary)">${winRate}%</div>
      <div class="sub-value" style="color: var(--muted)">${wins.length} Win / ${losses.length} Loss</div>
    </div>
    <div class="card">
      <div class="label">Efficiency (PF)</div>
      <div class="value">${profitFactor}</div>
      <div class="sub-value" style="color: var(--muted)">Max DD: ${maxDD.toFixed(2)}%</div>
    </div>
    <div class="card">
      <div class="label">Portfolio Value</div>
      <div class="value">${formatKES(finalBalanceKES)}</div>
      <div class="sub-value" style="color: var(--muted)">Init: ${formatKES(startBalanceKES)}</div>
    </div>
  </div>

  <div class="grid-stats">
    <div class="card">
      <div class="label">Risk Statistics</div>
      <div class="value" style="font-size: 18px;"><span style="color: var(--success)">+${formatKES(avgWinKES)}</span> <span style="color:var(--muted);font-size:12px">vs</span> <span style="color: var(--danger)">-${formatKES(avgLossKES)}</span></div>
      <div class="sub-value" style="color: var(--muted)">Avg. Outcome per Session</div>
    </div>
    <div class="card">
      <div class="label">Peak Deviations</div>
      <div class="value" style="font-size: 18px;"><span style="color: var(--success)">${formatKES(bestTradeKES)}</span> <span style="color:var(--muted);font-size:12px">/</span> <span style="color: var(--danger)">${formatKES(worstTradeKES)}</span></div>
      <div class="sub-value" style="color: var(--muted)">Best vs Worst Trade Execution</div>
    </div>
  </div>

  <div class="card" style="margin-bottom: 1.5rem;">
    <div class="section-title">EQUITY GROWTH (KES)</div>
    <div class="chart-container">
      <canvas id="equityChart"></canvas>
    </div>
  </div>

  <div class="flex-row">
    <div class="card">
      <div class="section-title">TRANSACTION LOG</div>
      <table>
        <thead>
          <tr>
            <th>Timestamp</th>
            <th>Dir</th>
            <th>Result</th>
            <th>Net Profit</th>
            <th>Account</th>
          </tr>
        </thead>
        <tbody id="tradeTable"></tbody>
      </table>
    </div>
    <div class="card">
      <div class="section-title">PERIODIC PERFORMANCE</div>
      <div style="height: 250px;">
        <canvas id="monthlyChart"></canvas>
      </div>
    </div>
  </div>
</div>

<script>
const trades = ${JSON.stringify(trades)};
const KES_RATE = ${KES_RATE};

Chart.defaults.color = '#94a3b8';
Chart.defaults.borderColor = 'rgba(255, 255, 255, 0.1)';

function formatKESJS(val) {
  return new Intl.NumberFormat('en-KE', { style: 'currency', currency: 'KES', maximumFractionDigits: 0 }).format(val);
}

function formatDateJS(dateStr) {
  const date = new Date(dateStr);
  const day = date.getDate();
  const month = date.toLocaleString('en-GB', { month: 'short' });
  const year = date.getFullYear();
  const j = day % 10, k = day % 100;
  let suffix = "th";
  if (j == 1 && k != 11) suffix = "st";
  if (j == 2 && k != 12) suffix = "nd";
  if (j == 3 && k != 13) suffix = "rd";
  return day + suffix + " " + month + " " + year;
}

// 1. Equity Chart
new Chart(document.getElementById('equityChart'), {
  type: 'line',
  data: {
    labels: trades.map((t, i) => i + 1),
    datasets: [{
      label: 'Balance',
      data: trades.map(t => t.balance * KES_RATE),
      borderColor: '#3b82f6',
      backgroundColor: 'rgba(59, 130, 246, 0.1)',
      borderWidth: 2,
      fill: true,
      tension: 0.4,
      pointRadius: 0,
      pointHoverRadius: 5
    }]
  },
  options: {
    responsive: true, maintainAspectRatio: false,
    plugins: { legend: { display: false } },
    scales: {
      x: { grid: { display: false } },
      y: { ticks: { callback: v => 'KSh ' + v.toLocaleString() } }
    }
  }
});

// 2. Monthly P&L
const months = {};
trades.forEach(t => {
  const d = new Date(t.exitTime);
  const key = d.toLocaleString('default', { month: 'short' }) + ' ' + d.getFullYear().toString().slice(2);
  months[key] = (months[key] || 0) + (t.profit * KES_RATE);
});

new Chart(document.getElementById('monthlyChart'), {
  type: 'bar',
  data: {
    labels: Object.keys(months),
    datasets: [{
      data: Object.values(months),
      backgroundColor: Object.values(months).map(v => v >= 0 ? '#22c55e' : '#ef4444'),
      borderRadius: 6
    }]
  },
  options: {
    responsive: true, maintainAspectRatio: false,
    plugins: { legend: { display: false } }
  }
});

// 3. Trade Table
const table = document.getElementById('tradeTable');
trades.slice().reverse().forEach(t => {
  const row = table.insertRow();
  const dateStr = formatDateJS(t.exitTime);
  const typeClass = t.direction === 'BUY' ? 'bg-blue' : 'bg-danger';
  const profitKES = t.profit * KES_RATE;
  const profitColor = profitKES >= 0 ? '#4ade80' : '#f87171';

  row.innerHTML = \`
    <td style="white-space: nowrap; color: var(--muted); font-size: 12px;">\${dateStr}</td>
    <td><span class="badge \${typeClass}">\${t.direction}</span></td>
    <td><span class="badge bg-muted">\${t.reason} \${t.isBreakeven ? 'BE' : ''}</span></td>
    <td style="color: \${profitColor}; font-weight: 600;">\${profitKES >= 0 ? '+' : ''}\${formatKESJS(profitKES)}</td>
    <td style="font-weight: 500;">\${formatKESJS(t.balance * KES_RATE)}</td>
  \`;
});
</script>
</body>
</html>`;

  fs.writeFileSync(OUTPUT_PATH, html);
  console.log(`\n✨ Dark Mode KES Dashboard generated: ${OUTPUT_PATH}`);
}

generate();

#!/usr/bin/env node

/**
 * 5-10-20 EMA Scalping Strategy
 * M5 Execution on EURUSD — IC Markets cTrader
 */

import fs from "fs";
import { ICMarketsClient } from "./icmarkets.js";
import { config } from "./config.js";
import { generateSignal } from "./indicators.js";
import { RiskManager } from "./risk-manager.js";

const STATE_FILE = "state.json";
const AUTO_EXECUTE = process.argv.includes("--auto-execute");
const PAIRS = config.tradingPairs;

const icmarkets = new ICMarketsClient();
const riskManager = new RiskManager(config);
const pairState = new Map();

function getState(pair) {
  if (!pairState.has(pair)) {
    pairState.set(pair, {
      candleCache: [],
      activeTrades: [],
      lastLogTime: 0,
      needsRefresh: true
    });
  }
  return pairState.get(pair);
}

async function run() {
  console.log(`\n${"═".repeat(60)}`);
  console.log(`   5-10-20 EMA SCALPING BOT — EURUSD M5`);
  console.log(`  Mode: ${AUTO_EXECUTE ? " AUTO-EXECUTE" : " MONITOR ONLY"}`);
  console.log(`${"═".repeat(60)}\n`);

  await icmarkets.connect();
  await icmarkets.authenticate();

  loadState();

  for (const pair of PAIRS) {
    await reconcileAccount(pair);
    await icmarkets.subscribeTicks(pair);
  }

  icmarkets.on(2126, (payload) => handleExecutionEvent(payload));

  setInterval(tick, config.pollIntervalSeconds * 1000);
}

async function tick() {
  const timestamp = new Date().toLocaleTimeString();
  const now = new Date();

  const h   = now.getUTCHours();
  const day = now.getUTCDay();
  if (day === 0 || day === 6 || h < config.sessionStartUTC || h >= config.sessionEndUTC) {
    process.stdout.write(`[${timestamp}]  Outside trading session (${h}:00 UTC)\r`);
    return;
  }

  for (const pair of PAIRS) {
    await tickPair(pair, timestamp).catch(err => console.error(`  ❌ ${pair} error:`, err.message));
  }
}

async function tickPair(pair, timestamp) {
  const state = getState(pair);
  const now   = Date.now();
  const isJPY = pair.includes("JPY");

  // 1. Fetch candles (rolling 100-candle window)
  if (state.needsRefresh || state.candleCache.length < 30) {
    state.candleCache = await icmarkets.getCandles(pair, config.granularity, 100);
    state.needsRefresh = false;
  }

  if (state.candleCache.length < 22) return;

  // 2. Generate signal
  const signal = generateSignal(state.candleCache, {
    pipBuffer: config.strategy.pipBuffer,
    rrRatio:   config.strategy.rrRatio,
    isJPY,
  });

  // Log status every minute
  if (now - (state.lastLogTime || 0) > 60000) {
    console.log(
      `[${timestamp}] ${pair} | Trend: ${signal.trend.toUpperCase()} | ` +
      `EMA5: ${signal.ema5} EMA10: ${signal.ema10} EMA20: ${signal.ema20} | ` +
      `Signal: ${signal.signal.toUpperCase()}`
    );
    if (signal.signal !== 'none') console.log(`  → ${signal.reason}`);
    state.lastLogTime = now;
  }

  if (signal.signal === 'none') return;

  // 3. Trade gate
  if (state.activeTrades.length >= config.maxTradesPerPair) return;

  const action = signal.signal.toUpperCase(); // 'BUY' | 'SELL'

  console.log(
    `\n⚡ [${timestamp}] ${pair} ${action} | ` +
    `Entry: ${signal.entry} SL: ${signal.sl} TP: ${signal.tp} | ` +
    `Risk: ${signal.riskPips}p Reward: ${signal.rewardPips}p`
  );

  if (!AUTO_EXECUTE) return;

  try {
    const units = riskManager.calculateVolume(pair, signal.riskPips, signal.entry);
    if (units <= 0) return;

    const res = await icmarkets.openPosition(pair, action, units, signal.sl, signal.tp);
    if (res && res.positionId) {
      state.activeTrades.push({ id: String(res.positionId), direction: action, pair, entry: signal.entry });
      saveState();
    }
  } catch (err) {
    console.error(`  ❌ Trade failed:`, err.message);
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function handleExecutionEvent(payload) {
  if (payload.executionType === "DEAL_FILLED" || payload.executionType === 4) {
    const deal = payload.deal;
    if (deal && deal.closePositionDetail) {
      const positionId = String(deal.positionId);
      console.log(`    Position ${positionId} closed.`);
      for (const [, state] of pairState) {
        state.activeTrades = state.activeTrades.filter(t => t.id !== positionId);
      }
      saveState();
    }
  }
}

async function reconcileAccount(pair) {
  const state = getState(pair);
  try {
    const positions = await icmarkets.reconcile();
    const symbolId = icmarkets._resolveSymbolId(pair);
    state.activeTrades = positions
      .filter(p => p.tradeData && String(p.tradeData.symbolId) === String(symbolId))
      .map(p => ({ id: String(p.positionId), direction: p.tradeData.tradeSide, pair }));
    saveState();
  } catch (err) {}
}

function loadState() {
  if (fs.existsSync(STATE_FILE)) {
    try {
      const data = JSON.parse(fs.readFileSync(STATE_FILE, "utf8"));
      if (data.activeTrades) {
        // Migration: flat activeTrades array — no per-pair state needed
      }
    } catch (err) {}
  }
}

function saveState() {
  const allTrades = [];
  for (const [, state] of pairState) allTrades.push(...state.activeTrades);
  fs.writeFileSync(STATE_FILE, JSON.stringify({ activeTrades: allTrades }, null, 2));
}

run().catch(console.error);

