  if (!pairState.has(pair)) {
    pairState.set(pair, {
      candleCache: [],
      activeTrades: [],
      lastLogTime: 0,
      needsRefresh: true
    });
  }
  return pairState.get(pair);
}

async function run() {
  console.log(`\n${"═".repeat(60)}`);
  console.log(`   5-10-20 EMA SCALPING BOT — EURUSD M5`);
  console.log(`  Mode: ${AUTO_EXECUTE ? " AUTO-EXECUTE" : " MONITOR ONLY"}`);
