    console.error(`  ❌ Trade failed:`, err.message);
  }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function handleExecutionEvent(payload) {
  if (payload.executionType === "DEAL_FILLED" || payload.executionType === 4) {
    const deal = payload.deal;
    if (deal && deal.closePositionDetail) {
      const positionId = String(deal.positionId);
      console.log(`    Position ${positionId} closed.`);
      for (const [, state] of pairState) {
        state.activeTrades = state.activeTrades.filter(t => t.id !== positionId);
      }
      saveState();
    }
  }
}

async function reconcileAccount(pair) {
  const state = getState(pair);
  try {
    const positions = await icmarkets.reconcile();
    const symbolId = icmarkets._resolveSymbolId(pair);
    state.activeTrades = positions
      .filter(p => p.tradeData && String(p.tradeData.symbolId) === String(symbolId))
      .map(p => ({ id: String(p.positionId), direction: p.tradeData.tradeSide, pair }));
    saveState();
  } catch (err) {}
}

function loadState() {
  if (fs.existsSync(STATE_FILE)) {
    try {
      const data = JSON.parse(fs.readFileSync(STATE_FILE, "utf8"));
      if (data.activeTrades) {
        // Migration: flat activeTrades array — no per-pair state needed
      }
    } catch (err) {}
  }
}

function saveState() {
  const allTrades = [];
  for (const [, state] of pairState) allTrades.push(...state.activeTrades);
  fs.writeFileSync(STATE_FILE, JSON.stringify({ activeTrades: allTrades }, null, 2));
}

function getActiveSessionWindowUTC(now) {
  const windows = config.sessionWindowsUTC;
  if (!Array.isArray(windows) || windows.length === 0) {
    const h = now.getUTCHours() + (now.getUTCMinutes() / 60);
    return h >= config.sessionStartUTC && h < config.sessionEndUTC ? { name: "legacy" } : null;
  }

  const h = now.getUTCHours() + (now.getUTCMinutes() / 60);
  return windows.find(w => h >= w.start && h < w.end) || null;
}

run().catch(console.error);

/**
 * Trade Performance Analyzer & Dashboard
 * Generates a Daily PnL Calendar from trades_backtest.json or live trade data.
 */

import fs from "fs";

const FILE_PATH = "trades_backtest.json";

function analyze() {
  if (!fs.existsSync(FILE_PATH)) {
    console.log("❌ No trade data found. Run a backtest first.");
    return;
  }

  const data = JSON.parse(fs.readFileSync(FILE_PATH, "utf8"));
  const trades = data.trades || [];

  if (trades.length === 0) {
    console.log("⚠️ No trades to analyze.");
    return;
  }

  // Group by Date
  const dailyStats = {};
  trades.forEach(t => {
    const date = t.exitTime.split("T")[0]; // YYYY-MM-DD
    if (!dailyStats[date]) {
      dailyStats[date] = { profit: 0, count: 0, wins: 0 };
    }
    dailyStats[date].profit += t.profit;
    dailyStats[date].count += 1;
    if (t.profit > 0) dailyStats[date].wins += 1;
  });

  const sortedDates = Object.keys(dailyStats).sort();

  console.log(`\n═══  DAILY PERFORMANCE DASHBOARD (${data.type.toUpperCase()}) ═══`);
  console.log(`${"═".repeat(60)}`);
  console.log(`  DATE        | TRADES | WIN % | NET PnL ($)`);
  console.log(`${"-".repeat(60)}`);

  let totalProfit = 0;
  let greenDays = 0;
  let redDays = 0;

  sortedDates.forEach(date => {
    const stats = dailyStats[date];
    const winRate = ((stats.wins / stats.count) * 100).toFixed(0);
    const profitStr = stats.profit.toFixed(2).padStart(10);

    // Simple color coding (ANSI)
    const color = stats.profit > 0 ? "\x1b[32m" : "\x1b[31m";
    const reset = "\x1b[0m";

    console.log(`  ${date}  |   ${stats.count.toString().padEnd(2)}   |  ${winRate.toString().padStart(3)}% | ${color}${profitStr}${reset}`);

    totalProfit += stats.profit;
    if (stats.profit > 0) greenDays++;
    else redDays++;
  });

  console.log(`${"═".repeat(60)}`);
  console.log(`  SUMMARY STATISTICS`);
  console.log(`${"-".repeat(60)}`);
  console.log(`  Total Period   : ${sortedDates[0]} to ${sortedDates[sortedDates.length - 1]}`);
  console.log(`  Profitable Days: \x1b[32m${greenDays}\x1b[0m`);
  console.log(`  Losing Days    : \x1b[31m${redDays}\x1b[0m`);
  console.log(`  Batting Average: ${((greenDays / sortedDates.length) * 100).toFixed(1)}% (Green Day Ratio)`);
  console.log(`  Total Net PnL  : $${totalProfit.toFixed(2)}`);
  console.log(`${"═".repeat(60)}\n`);
}

analyze();

